#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <ctype.h>
#define MAX 100005
#define MOD 1000000007

int dp[MAX][MAX];
char s[MAX];

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%s", s);
        int n = strlen(s);
        int K;
        scanf("%d", &K);
        // Initialize dp array
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= n; j++) {
                dp[i][j] = 0;
            }
        }
        // Compute dp array
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= i; j++) {
                if (s[i - 1] == '(') {
                    dp[i][j] = dp[i - 1][j + 1];
                } else {
                    dp[i][j] = dp[i - 1][j - 1] + 1;
                }
            }
        }
        // Find maximum length of non-regular subsequence
        int max_len = 0;
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= n; j++) {
                if (dp[i][j] > max_len) {
                    max_len = dp[i][j];
                }
            }
        }
        // Find lexicographically Kth subsequence
        int count = 0;
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= n; j++) {
                if (dp[i][j] == max_len) {
                    count++;
                    if (count == K) {
                        // Output lexicographically Kth subsequence
                        printf("%s\n", s);
                        break;
                    }
                }
            }
        }
        if (count < K) {
            printf("-1\n");
        }
    }
    return 0;
}

