import java.util.HashSet;
import java.util.TreeSet;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int n = s.length();
            int K = sc.nextInt();
            // Initialize dp array
            int[][] dp = new int[n + 1][n + 1];
            // Compute dp array
            for (int i = 1; i <= n; i++) {
                for (int j = 0; j <= i; j++) {
                    if (s.charAt(i - 1) == '(') {
                        dp[i][j] = dp[i - 1][j + 1];
                    } else {
                        dp[i][j] = dp[i - 1][j - 1] + 1;
                    }
                }
            }
            // Find maximum length of non-regular subsequence
            int max_len = 0;
            for (int i = 0; i <= n; i++) {
                for (int j = 0; j <= n; j++) {
                    if (dp[i][j] > max_len) {
                        max_len = dp[i][j];
                    }
                }
            }
            // Find lexicographically Kth subsequence
            Set<String> subsequences = new TreeSet<>();
            for (int i = 0; i <= n; i++) {
                for (int j = 0; j <= n; j++) {
                    if (dp[i][j] == max_len) {
                        String subsequence = s.substring(0, i);
                        subsequences.add(subsequence);
                    }
                }
            }
            // Output lexicographically Kth subsequence
            int count = 0;
            for (String subsequence : subsequences) {
                count++;
                if (count == K) {
                    System.out.println(subsequence);
                    break;
                }
            }
            if (count < K) {
                System.out.println(-1);
            }
        }
    }
}

